#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y; scanf("%d %d", &X, &Y);
        int d = X > Y ? X - Y : Y - X;
        int ans = (d + 1) / 2;
        printf("%d\n", ans);
    }
    return 0;
}

